public static long[][] solve(long[][] grid, long x, long y, long k) {
    // Create a copy of the grid to avoid modifying the original
    long[][] matrix = new long[grid.length][grid[0].length];
    for (int i = 0; i < grid.length; i++) {
        for (int j = 0; j < grid[i].length; j++) {
            matrix[i][j] = grid[i][j];
        }
    }

    // Extract the submatrix
    long[][] submatrix = new long[k][k];
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < k; j++) {
            submatrix[i][j] = matrix[(int)x + i][(int)y + j];
        }
    }

    // Reverse the submatrix
    long[][] reversedSubmatrix = new long[k][k];
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < k; j++) {
            reversedSubmatrix[i][j] = submatrix[k - 1 - i][j];
        }
    }

    // Replace the original submatrix with the reversed one
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < k; j++) {
            matrix[(int)x + i][(int)y + j] = reversedSubmatrix[i][j];
        }
    }

    return matrix;
}
